class Solution:
    def maxSumSubarray(self, s: str) -> int:
        n = len(s)
        maxSum = 0
        prefixSum = [0] * (n + 1)
        for i in range(n):
            prefixSum[i + 1] = prefixSum[i] + int(s[i])
        for i in range(n):
            for j in range(i, n):
                maxSum = max(maxSum, prefixSum[j + 1] - prefixSum[i])
        return maxSum

def main():
    s = input()
    solution = Solution()
    print(solution.maxSumSubarray(s))

if __name__ == '__main__':
    main()

