class Solution {
public:
    int maxSumSubarray(std::string& s) {
        int n = s.size();
        int maxSum = 0;
        int prefixSum[n + 1] = {0};
        for (int i = 0; i < n; i++) {
            prefixSum[i + 1] = prefixSum[i] + (s[i] - '0');
        }
        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j++) {
                maxSum = std::max(maxSum, prefixSum[j + 1] - prefixSum[i]);
            }
        }
        return maxSum;
    }
};

